mapper.select:
SELECT c.*, u.email AS user_email FROM user_consent c INNER JOIN users u ON u.id = c.user_id
AND (u.email LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%'))
AND c.consent_type = #{consentType}
AND c.agreed = TRUE AND c.revoked_at IS NULL
AND (c.agreed = FALSE OR c.revoked_at IS NOT NULL)
AND c.source = #{source}
AND c.created_at >= CONCAT(#{from}, ' 00:00:00')
AND c.created_at <= CONCAT(#{to}, ' 23:59:59')
ORDER BY c.id DESC LIMIT #{limit}
